package org.julio.springcloud.msvc.usuarios.clients;import org.springframework.cloud.openfeign.FeignClient;import org.springframework.http.ResponseEntity;import org.springframework.web.bind.annotation.DeleteMapping;import org.springframework.web.bind.annotation.PathVariable;@FeignClient(name = "mscv-cursos",url = "http://localhost:8002")public interface CursoClienteFeing {    @DeleteMapping("/eliminarcursoalumno/{id}")    void eliminarcursoalumno(@PathVariable Long id);}